"""
mkt-context: Psalms 75-77
Chapters: 75-77 (42 verses)
Run: python3 scripts/zc-context-psalms-75-77.py

Key context decisions:
- Psalm 75: Cup of wrath (v8) — ANE and prophetic cup-of-wrath tradition; horn lifting iconography
- Psalm 76: Asaph Zion victory hymn; Sennacherib 701 BC background; Salem = Jerusalem (earliest form)
- Psalm 77: Asaph/Jeduthun; 7 questions of vv7-9 probe covenant reliability; Exodus recollection pivot
"""
import json, pathlib

ROOT = pathlib.Path(__file__).parent.parent

def load_comm(source, book):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    if p.exists():
        return json.loads(p.read_text())
    return {}

def save_comm(source, book, data):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f'  wrote {p.relative_to(ROOT)}')

def merge_comm(existing, new_data):
    # INTENT: merge without overwriting any verse already present in existing
    # CHANGE? Do not alter the guard; concurrent agents depend on append-only behavior
    # VERIFY: run twice; second run should report identical byte count for psalms.json
    for ch, verses in new_data.items():
        if ch not in existing:
            existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]:
                existing[ch][v] = html

NEW_DATA = {"75": {"1": "<p><b>Ps 75: Asaph's Judgment Psalm — 'Do Not Destroy.'</b> The superscription 'Al-Tashcheth' (do not destroy) is a tune designation shared with Pss 57, 58, 59 — possibly the opening words of a known song to whose melody this psalm was sung, or a liturgical instruction against destroying the psalm's content. The Asaph guild (Pss 50, 73-83) were Levitical singers with a distinctive theological tradition emphasizing divine sovereignty over history.</p><p><b>'We give thanks to you, O God; we give thanks, for your name is near. People recount your wondrous deeds'</b> — the double <i>hodinu</i> (we give thanks) opens the psalm in the register of communal gratitude. 'Your name is near' (<i>qarov shemechah</i>) — divine nearness as the occasion of praise: the name is near because YHWH has acted within history in a way that can be reported (<i>sippur niphleotechah</i>, the recounting of wondrous deeds). The community's ongoing testimony of divine acts is the expression of the nearness of the divine name.</p>", "2": "<p><b>'At the set time that I appoint I will judge with equity'</b> — YHWH himself speaks: <i>moedim</i> (set times, appointed times — the same word for the covenant feast calendar). Divine judgment operates on a fixed schedule known only to YHWH. The 'set time' resonates with the prophetic tradition of <i>et</i> (appointed time): Hab 2:3 ('the vision awaits its appointed time'), Dan 8:19, 11:27, 35 — the eschatological calendar is fixed. The equity (<i>misharin</i>) of the judgment addresses the lament that the wicked currently prosper: the judgment is coming and will be perfectly proportioned.</p>", "3": "<p><b>'When the earth totters, and all its inhabitants, it is I who keep steady its pillars'</b> — the ANE cosmological image of the earth resting on pillars (<i>ammudim</i>) — the columns that support the flat earth above the cosmic waters. The earth 'tottering' in crisis is the dissolution of cosmic order, which the Psalter repeatedly associates with moral chaos (Ps 82:5). YHWH as the one who holds the earth's pillars steady is the creator maintaining cosmic stability against the entropy of human wickedness. Cf. 1 Sam 2:8 (Hannah's song: YHWH 'set the world on its pillars').</p>", "4": "<p><b>'I say to the boastful, Do not boast, and to the wicked, Do not lift up your horn'</b> — the divine speech continues. The 'horn' (<i>qeren</i>) in ANE iconography was the symbol of power and pride: warrior-kings wore horn-shaped helmets; the bull's horn was the emblem of strength. 'Lifting the horn' (<i>rum qeren</i>) is the physical gesture of aggressive self-assertion. YHWH forbids it to the wicked — the divine speech directly confronts the arrogance of the powerful who have forgotten the divine judgment of v2.</p>", "5": "<p><b>'Do not lift up your horn on high, or speak with haughty neck'</b> — 'with haughty neck' (<i>betzavar ataq</i>) — the lifted neck as the physical posture of arrogance: the head thrown back, the chin raised, looking down on others. This is the body language of the powerful oppressor in ANE relief art (kings trampling defeated enemies). The divine speech explicitly names and forbids the physical posture of pride.</p>", "6": "<p><b>'For not from the east or from the west and not from the wilderness comes lifting up'</b> — the geographic disclaimer: promotion/exaltation (<i>harim</i>, the lifting-up word of v4-5) does not originate from any point of the compass. 'East' (<i>meitze</i>), 'west' (<i>umimarav</i>), 'wilderness/south' (<i>umimidbar</i>) — the three geographic directions standing for the totality of human sources of power. Human exaltation comes from nowhere human — neither imperial power (east = Mesopotamia/Persia), maritime power (west = Mediterranean/Egypt), nor nomadic military power (south = wilderness).</p>", "7": "<p><b>'But it is God who executes judgment, putting down one and lifting up another'</b> — <i>Elohim shofet zeh yashpil vzeh yarum</i> — the central theological claim: YHWH alone controls the rise and fall of powers. This is the key text for the Psalter's theodicy: the wicked prosper and the righteous suffer only provisionally; YHWH is the sovereign who ultimately determines which direction the trajectory goes. Daniel's theology of divine sovereignty over kingdoms (Dan 2:21: 'He deposes kings and raises up kings') derives from this tradition.</p>", "8": "<p><b>'For in the hand of the LORD there is a cup with foaming wine, well mixed, and he pours out from it, and all the wicked of the earth shall drain it down to the dregs'</b> — the cup of divine wrath is one of the most pervasive ANE and biblical images: YHWH's judgment administered as a cup of wine that produces reeling, stupor, and collapse. The cup appears in Jer 25:15-17 (YHWH's cup poured to all nations), Ezek 23:32-34 (Oholibah's cup of judgment), Hab 2:16 (shame-cup), Isa 51:17-22 (Jerusalem's cup of staggering), and Rev 14:10; 16:19 (the cup of God's wrath). The dregs (<i>shmarim</i>) were the sediment at the bottom of the wine — the worst, most concentrated portion, which the wicked must consume entirely.</p>", "9": "<p><b>'But I will declare it forever; I will sing praises to the God of Jacob'</b> — the psalmist's own vow: the declaration of divine judgment becomes the content of perpetual praise. The 'God of Jacob' — the covenant-identification: not the God of abstract philosophy but the God who entered covenant with a specific person (Jacob) and his descendants. The cup of wrath for the wicked is the same God's covenant faithfulness to Jacob's children.</p>", "10": "<p><b>'All the horns of the wicked I will cut off, but the horns of the righteous shall be lifted up'</b> — the reversal that closes the psalm: the wicked's horn-lifting (vv4-5) is cut off; the righteous person's horn is lifted by divine action. The same horn-imagery — now the divine response completes the contrast. The righteous are not self-promoted (the warning of vv4-5) but exalted by YHWH. This is the pattern of Ps 113:7-8 and Hannah's song (1 Sam 2:4-8): divine reversal of human status hierarchies.</p>"}, "76": {"1": "<p><b>Ps 76: Asaph's Zion Victory Hymn — Sennacherib's Shadow.</b> This psalm is widely connected to YHWH's deliverance of Jerusalem from Sennacherib's Assyrian army (701 BC), when 185,000 Assyrian soldiers were struck dead overnight (2 Kgs 19:35-36; Isa 37:36-37). Whether or not the specific historical occasion is Sennacherib, the psalm celebrates a decisive divine military victory that took place at or near Jerusalem. 'God is known in Judah; his name is great in Israel' — <i>noda</i> (is known, Niphal perfect) — the divine knowledge spreads through the victory: YHWH's name becomes great because of what he has done.</p>", "2": "<p><b>'His abode has been established in Salem, his dwelling place in Zion'</b> — <i>Salem</i> is the earliest form of the name Jerusalem: Melchizedek was 'king of Salem' in Gen 14:18, and the Amarna letters refer to the city as Urusalem. The shortened form Salem appears here and in Ps 76:2 as a poetic abbreviation. YHWH's <i>sukko</i> (tent/tabernacle/booth) in Salem — the divine dwelling evokes both the wilderness Tent of Meeting and Solomon's temple. The spatial claim: Jerusalem is where YHWH has chosen to place his name (Deut 12:5).</p>", "3": "<p><b>'There he broke the flashing arrows, the shield, the sword, and the weapons of war'</b> — 'there' (<i>sham</i>) — the specific location of the divine weapons-destruction. The list: <i>reshpe qeshet</i> (flashing arrows/coals of the bow), shield (<i>magen</i>), sword (<i>cherev</i>), and war (<i>milchamah</i>) — a comprehensive military arsenal reduced to nothing by divine action. The 'breaking' of weapons at the divine dwelling is the enactment of the eschatological peace vision of Isa 2:4/Mic 4:3 ('they shall beat their swords into plowshares').</p>", "4": "<p><b>'Glorious are you, more majestic than the mountains full of prey'</b> — <i>naor attah adir meharerei taraph</i> — 'more majestic than the mountains of prey/plunder.' The 'mountains of prey' (<i>harei taraph</i>) may refer to the mountains where predatory animals (lions, wolves) take their prey — YHWH surpasses even the most fearsome natural power. Alternatively, if referring to enemy mountains (Assyria's mountain-gods, or the mountain fortresses of surrounding powers), YHWH's glory exceeds their military power.</p>", "5": "<p><b>'The stouthearted were stripped of their spoil; they sank into sleep; none of the warriors could use his hands'</b> — the overnight destruction of the enemy force: 'sank into sleep' (<i>namu shnatam</i>) — the sleep of death, the sleep that does not end. The warriors' inability to use their hands is the divine disabling of military capability. This matches the 2 Kgs 19:35 account: the Assyrians were found dead in the morning. The ANE military imagery of stripping armor from fallen enemies is the background for 'stripped of their spoil.'</p>", "6": "<p><b>'At your rebuke, O God of Jacob, both rider and horse lay stunned'</b> — <i>gearatchah</i> (your rebuke) — the divine rebuke as the weapon that overwhelms the enemy. The same <i>gaar</i> (rebuke) used of the cosmic waters (Ps 104:7), the enemies of the cosmos (Ps 80:16), and the storm forces (Ps 106:9). YHWH's rebuke is a word-weapon that needs no sword. 'Horse and rider lay stunned/in deep sleep' (<i>nirdam</i>, a cognate of the sleep of death) — echoes Exod 15:1 ('horse and rider he has thrown into the sea'): the Exodus pattern repeated at Jerusalem.</p>", "7": "<p><b>'But you, you are to be feared! Who can stand before you when once your anger is roused?'</b> — the rhetorical question of divine invincibility. <i>Mi ya'amod lefanechah</i> (who can stand before you?) — the divine <i>panim</i> (face/presence) before which no human or cosmic power can maintain standing. This formula echoes the Sinai theophany where Israel could not stand before YHWH and had to retreat (Exod 20:18-19). The rhetorical question expects the answer: no one.</p>", "8": "<p><b>'From the heavens you uttered judgment; the earth feared and was still'</b> — the cosmic court: divine judgment descends from the heavenly tribunal to the earthly realm. 'The earth feared and was still' (<i>haaretz yareah vashaqatah</i>) — the earth's response to divine judgment is reverential silence. ANE divine court proceedings similarly depict cosmic silence when the great god speaks: the earth's stillness is the creaturely response to the creator's decree.</p>", "9": "<p><b>'When God arose to establish judgment, to save all the humble of the earth'</b> — the divine arising from the heavenly throne to execute judgment. 'The humble of the earth' (<i>anavei aretz</i>) — the <i>anavim</i> (humble, lowly, afflicted) are the protected class in the covenant: the widows, orphans, sojourners, and economically vulnerable whom YHWH specifically defends (Ps 72:4; Isa 11:4; Zeph 3:12). The divine arising produces two simultaneous effects: judgment on the wicked and salvation for the humble.</p>", "10": "<p><b>'Surely the wrath of man shall praise you; the remnant of wrath you will put on like a belt'</b> — a difficult verse. 'The wrath of man shall praise you' — human anger and wickedness are forced into divine service: even the enemy's aggression becomes an occasion for YHWH's glory. The 'remnant of wrath' (<i>she'erit chemot</i>) that YHWH 'puts on like a belt' — the leftover fury of the defeated enemy is harnessed by YHWH, who girds himself with even the residue of human rage. The sovereignty of YHWH incorporates even hostile human will into his purposes.</p>", "11": "<p><b>'Make your vows to the LORD your God and perform them; let all around him bring gifts to him who is to be feared'</b> — the call to covenant response: the nations surrounding YHWH's territory should bring tribute (<i>shay</i>, gift/tribute) to the one who is awesome (<i>lamora</i>, to the Feared One). ANE vassal states brought annual tribute to the great king who had demonstrated his superiority. Ps 76 applies this political theology to YHWH: the divine victory over the enemy requires the tribute-response of all surrounding peoples. The 'vow' (<i>neder</i>) + fulfillment (<i>shallemu</i>) is the covenant-grateful response to rescue.</p>", "12": "<p><b>'He cuts off the spirit of princes; he is feared by the kings of the earth'</b> — the final divine act: <i>yivtzor ruach negidim</i> (he clips/cuts off the spirit of princes/leaders). The 'spirit' of rulers is their executive capacity, their will to act — YHWH cuts it off, rendering them incapable. 'Feared by the kings of the earth' (<i>nora lemalkhei aretz</i>) — the psalm closes with the universal scope of YHWH's sovereignty: the kings who brought their armies against Jerusalem are now the fearers of the God who defeated them. The circle closes: the psalm opened with YHWH's name being great in Israel (v1) and ends with his being feared by all earth's kings.</p>"}, "77": {"1": "<p><b>Ps 77: Asaph's Journey from Lament to Exodus Memory.</b> The psalm is attributed to Asaph and directed 'to Jeduthun' — Jeduthun (also called Ethan) was one of the three chief Levitical musician guilds alongside Asaph and Heman (1 Chr 16:41-42; 25:1-6). The Jeduthun guild is associated with Pss 39, 62, 77. The psalm has a precise two-part structure: personal lament (vv1-9) and historical recollection of the Exodus (vv11-20), joined by the theological pivot of v10. This structure — crisis drives the worshiper back to foundational salvation history — is the Psalter's characteristic response to present suffering.</p><p><b>'I cried out to God with my voice'</b> — <i>qoli el-Elohim</i> (my voice to God) — the cry is physical and loud. The redundancy ('cried with my voice') emphasizes the urgency and audibility of the lament: not merely inward anxiety but voiced protest directed toward God.</p>", "2": "<p><b>'In the day of my trouble I seek the Lord; in the night my hand is stretched out without wearying; my soul refuses to be comforted'</b> — 'my hand stretched out without wearying' (<i>yadi laylah nigerah velo tapug</i>) — the hand extended in prayer posture through the night without stopping (the gesture of Exod 17:11-12, Moses' hands raised in prayer during the battle). 'My soul refuses to be comforted' (<i>meat hinnachem naphshi</i>) — the most desperate description of grief in the Psalter: the usual mechanisms of comfort (prayer, community, ritual) have failed. The soul has closed itself off from consolation.</p>", "3": "<p><b>'When I remember God, I moan; when I meditate, my spirit faints'</b> — the reversal of normal theology: remembering God produces not comfort but groaning. In the lament psalms, the memory of God is supposed to generate confidence (cf. Ps 42:4-8); here it does the opposite. The crisis is so acute that even the thought of God increases the pain. This is the experience of divine abandonment — where the God who should be the source of rescue seems instead to be the source of the distress.</p>", "4": "<p><b>'You hold my eyelids open; I am so troubled that I cannot speak'</b> — 'you hold my eyelids open' (<i>achazta shemurot einai</i>) — YHWH himself prevents the psalmist from sleeping. The insomnia is divine: God keeps the eyes open. The sleeplessness that in Ps 63:6 produces joyful nighttime meditation here produces nothing but speechless anguish. 'Cannot speak' (<i>niphamu velo adabber</i>) — the pre-lament silence is worse than the lament: the tongue cannot even find the words of distress.</p>", "5": "<p><b>'I consider the days of old, the years long ago'</b> — the first movement toward salvation history: the psalmist begins to look backward. 'Days of old' (<i>yemei qedem</i>) and 'years of long ago' (<i>shenot olamim</i>) — the deep past of YHWH's saving acts. This retrospection is the structural bridge from individual lament (vv1-4) toward the Exodus recollection (vv11-20). The theological strategy: when the present is unreadable, seek the God of the past.</p>", "6": "<p><b>'I said, Let me remember my song in the night; let me meditate in my heart. Then my spirit made a diligent search'</b> — the nighttime song as the object of meditation. 'My song in the night' (<i>shirti balaylah</i>) — probably a lament or praise song known from the sanctuary that the psalmist rehearses in the dark. 'My spirit made a diligent search' (<i>vayechafer ruchi</i>, Piel of <i>chapar</i> = to dig, search carefully) — an intensive investigation of the spirit: probing one's own interior for some vestige of the salvation-experience.</p>", "7": "<p><b>'Will the Lord spurn forever, and never again be favorable?'</b> — the first of seven questions (vv7-9) that mark the nadir of the psalm. These questions are not rhetorical but genuine: the psalmist does not know the answers. They probe the possibility that YHWH's covenant character has fundamentally changed. In ANE thought, a patron deity could permanently abandon a devotee — divine faithfulness was not unconditional. The psalmist brings this possibility before YHWH as the most terrifying hypothesis.</p>", "8": "<p><b>'Has his steadfast love forever ceased? Are his promises at an end for all time?'</b> — 'his steadfast love forever ceased' (<i>gamer chesed leolam</i>) — <i>gavar</i> (to be complete, come to an end) applied to <i>chesed</i>: has the covenant-love run out, been used up? The permanence of divine <i>chesed</i> is the foundational promise (Ps 136: 'his steadfast love endures forever'); the question interrogates that permanence. 'His promises at an end' (<i>gamar omer ledor vador</i>) — the divine speech-act that created the covenant: has the word stopped?</p>", "9": "<p><b>'Has God forgotten to be gracious? Has he in anger shut up his compassion?'</b> — 'Has God forgotten to be gracious?' (<i>hashach chonnot El</i>) — divine forgetfulness is the theological impossibility the psalmist dares to voice. YHWH's name is 'gracious' (<i>channun</i>) by self-definition (Exod 34:6); has he forgotten his own character? 'Shut up his compassion' (<i>qaphatz beaph rachamav</i>) — the womb-mercy (<i>rachamim</i>) sealed off. Seven questions, seven painful lances into the covenant's reliability. The sevenfold structure mirrors the seven-day creation: YHWH created the world in seven acts of blessing; has he now sealed it in seven acts of withdrawal?</p>", "10": "<p><b>'Then I said, It is my grief that the right hand of the Most High has changed'</b> — the theological pivot of the entire psalm. <i>Chaloti hi</i> — this verse is difficult and contested; the MKT reads it as the psalmist's self-diagnosis: 'This is my grief/wound — the changing of the right hand of the Most High.' The key insight: the problem may be the psalmist's perception, not a change in YHWH. YHWH's right hand — the hand of saving action — has not actually changed; the psalmist's perspective has been distorted by suffering. This opens the door to the second movement of the psalm: recall what the right hand has actually done.</p>", "11": "<p><b>'I will remember the deeds of the LORD; yes, I will remember your wonders of old'</b> — the decisive turn: <i>ezkor maale-Yah</i> (I will remember the deeds of Yah). The first person singular future (<i>ezkor</i>, I will remember) is an act of will, a choice made against the grain of the painful experience. 'Wonders of old' (<i>miphleotechah miqqedem</i>) — the <i>niphlaot</i> (wondrous acts) are specifically the Exodus events: the sea-splitting, the pillar of fire, the plagues. The psalmist deliberately anchors personal crisis in the community's foundational salvation narrative.</p>", "12": "<p><b>'I will ponder all your work, and meditate on your mighty deeds'</b> — <i>vehaggiti</i> (I will meditate, voiced self-talk) and <i>asicha</i> (I will contemplate) — both verbs of deliberate sustained attention. The psalmist commits to the practice of meditation (<i>hagah</i>, the same word as Ps 1:2) on the divine acts. The practice of meditative rehearsal of salvation history is the cognitive-liturgical practice that transforms lament into praise.</p>", "13": "<p><b>'Your way, O God, is holy. What god is great like our God?'</b> — <i>baqodesh darkechah El</i> (in holiness is your way, O God) — YHWH's way/path (<i>derek</i>) is characterized by holiness: moral purity, separation from all that corrupts. The rhetorical question — 'what god is great like our God?' (<i>mi El gadol ke-Elohim</i>) — is a direct polemic against ANE polytheism: YHWH is incomparable. Exod 15:11 uses the same rhetorical question immediately after the sea-crossing: 'Who is like you, O LORD, among the gods?'</p>", "14": "<p><b>'You are the God who works wonders; you have made known your might among the peoples'</b> — <i>El oseh phele</i> (God who does wonders) — the same <i>phele/niphla</i> vocabulary as vv11-12: the wondrous acts are now identified as YHWH's specific divine quality. 'Made known your might among the peoples' (<i>hoda-ta baamim uzechah</i>) — the Exodus events were witnessed by Egypt and the surrounding peoples: Exod 9:16 ('I have raised you up to show my power, so that my name may be proclaimed in all the earth'), Josh 2:9-11 (Rahab's testimony of the nations hearing about YHWH's deeds).</p>", "15": "<p><b>'You with your arm redeemed your people, the children of Jacob and Joseph'</b> — 'the arm of YHWH' (<i>zero'a</i>) is the Exodus vocabulary: Exod 6:6 ('I will redeem you with an outstretched arm'); Deut 4:34; 26:8. The divine arm is the instrument of salvific power. 'Children of Jacob and Joseph' — the double patriarchal reference is unusual: normally 'Jacob and Israel.' Joseph represents the northern tribes (Ephraim and Manasseh) — the inclusion of Joseph alongside Jacob suggests the psalm addresses all twelve tribes, reunited in the memory of the common Exodus ancestor.</p>", "16": "<p><b>'When the waters saw you, O God, when the waters saw you, they were afraid; indeed, the deep trembled'</b> — the cosmic sea-splitting recollection begins. The waters as sentient respondents to divine presence: they 'saw' (<i>rauchah</i>) and 'were afraid' (<i>yachailu</i>). This is the mythological-poetic register of the Exodus: the sea does not merely part because of wind (Exod 14:21) but actively responds to divine presence with fear. The 'deep' (<i>tehomot</i>) — the primordial depth of creation (Gen 1:2) — trembled. Creation itself responds to the creator's act of redemption.</p>", "17": "<p><b>'The clouds poured out water; the skies gave forth thunder; your arrows flashed on every side'</b> — the Exodus theophany as cosmic storm: thunder (<i>qol natenu shaqim</i>, the skies gave their voice), arrows (<i>chitzechah</i> = lightning). This is the same storm-language of Ps 29 applied to the Exodus event: YHWH as the divine storm-lord demonstrating his power at the sea. Exod 14:24 records that YHWH looked from the pillar of fire and cloud and threw the Egyptian army into panic — the storm-theophany is part of the Exodus narrative.</p>", "18": "<p><b>'The crash of your thunder was in the whirlwind; your lightnings lit up the world; the earth trembled and shook'</b> — the full Sinai-type theophany applied to the sea-event. The 'whirlwind' (<i>galgal</i>, the wheel or whirling) — the divine chariot-storm (cf. Ezek 1). The earth trembling and shaking (<i>ratash vetirash haaretz</i>) is the cosmic response to divine presence. The Psalter consistently reads the Exodus as a creation-event: YHWH's saving of Israel is as cosmically significant as the original creation, requiring the same response from the created order.</p>", "19": "<p><b>'Your way was through the sea, your path through the great waters; yet your footprints were unseen'</b> — the most theologically suggestive verse of the psalm. YHWH's path was through the sea, yet 'your footprints were unseen' (<i>ve'ikevotechah lo noda'u</i>). The divine way is real but invisible: YHWH acts in history in ways that leave no directly traceable footprints. The sea closed again after Israel passed through — the path was obliterated. This is a theology of divine hiddenness: YHWH is sovereignly active but not empirically traceable. The faith of v11 ('I will remember') is required precisely because the footprints are unseen.</p>", "20": "<p><b>'You led your people like a flock by the hand of Moses and Aaron'</b> — the psalm closes with the shepherd-image of divine leadership. YHWH as shepherd, Moses and Aaron as the human instruments. The Exodus rescue is not directly executed by Moses or Aaron but by YHWH 'through their hand' (<i>beyad Moshe veAharon</i>) — divine agency through human mediation. The flock image echoes Ps 78:52; 80:1 and connects to the Good Shepherd language of John 10 and the shepherd-king theology of Ezek 34. The lament that opened with 'my soul refuses to be comforted' (v2) closes with the image of the divine shepherd comforting and leading the flock: the Exodus memory provides what personal experience could not.</p>"}}

if __name__ == '__main__':
    book = 'psalms'
    source = 'mkt-context'
    existing = load_comm(source, book)
    merge_comm(existing, NEW_DATA)
    save_comm(source, book, existing)
    for ch, vv in NEW_DATA.items():
        saved = existing.get(ch, {})
        missing = [v for v in vv if v not in saved]
        print(f'  ch {ch}: {len(vv)} entries, {len(missing)} missing after merge')
